import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import Image from './phonk_wallpaper.jpg';
import reportWebVitals from './reportWebVitals';
import Header from './header.js';
import Footer from './footer.js';

import News from './news.js';

import { BrowserRouter, Routes, Route } from "react-router-dom";

let flag = false
let counter = 0

function LastNews() {
  return (
    <div>
      <p>{flag === true ? "Не наводися сюда" : "Тут вообще должна быть самая последняя новость, но так как я очень ленивый, здесь просто написана всякая фигня : )"}</p>
      <p>{counter > 5 ? "Хватит наводиться сюда, иди на другие кнопки тыкай : )" : ""}</p>
      <p class="name_card">{counter > 15 ? "Не, ну ты перегибаешь" : ""}</p>
    </div>
  )
}

function MouseOver() {
  flag = true
  root.render(<MainPage />)
}

function MouseOut() {
  flag = false
  root.render(<MainPage />)
}

function MainPage() {
  return(
  <div id="main_page">
    <Header />
    <div id="content">
      <div id="news" onMouseOver={MouseOver} onMouseOut={MouseOut}>
        <p class="name_card">Новости</p>
        <div id="news_place">
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<Layout />}>
              <Route index element={<Home />} />
              <Route path="blogs" element={<Blogs />} />
              <Route path="contact" element={<Contact />} />
              <Route path="*" element={<NoPage />} />
            </Route>
          </Routes>
        </BrowserRouter>
        </div>
      </div>
      <div id="game_shop" class="game_item_shop_card">
        <p class="name_card">Магазин</p>
        <img src={Image} alt="Хаха"/>
      </div>
      <div id="item_store" class="game_item_shop_card">
        <p class="name_card">Торговая площадка</p>
        <img src={Image} alt="Хаха"></img>
      </div>
    </div>
    <Footer />
  </div>
  )
}


const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<MainPage />);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals(console.log);
